function shouldUseDarkTheme(){const e=localStorage.getItem("darkMode"),t=window.matchMedia("(prefers-color-scheme: dark)").matches;return e==="true"||e===null&&t}function applyThemeClass(e){document.documentElement.classList.toggle("dark",e)}function toggleDarkMode(){const e=!document.documentElement.classList.contains("dark");applyThemeClass(e),localStorage.setItem("darkMode",e),updateThemeIcons(e)}function updateThemeIcons(e){const t=document.getElementById("moon-icon"),n=document.getElementById("sun-icon");!t||!n||(t.classList.toggle("hidden",e),n.classList.toggle("hidden",!e))}applyThemeClass(shouldUseDarkTheme()),document.addEventListener("DOMContentLoaded",()=>{updateThemeIcons(document.documentElement.classList.contains("dark"))});
